import React, { useState, useEffect, useRef } from "react";
import {
  Box,
  Button,
  CircularProgress,
  Typography,
  Dialog,
  DialogContent,
  TextField,
} from "@mui/material";
import { toast } from "react-toastify";
import { checkVerifyRemitter } from "../../api/login/Login";
import { usePpiBankTransfer } from "./BankTransferPPIProvider";
import PpiPageLayout from "./PpiPageLayout";
import "./PpiTransactionReport.css";
import ppibank from "../../asesets/bill-payments/ppibank.png"; // your background image

/* ---------- design tokens (light theme) ---------- */
const BG_BASE = "#F5F4FC";
const PANEL = "#FFFFFF";
const NAVY = "#2A2359";      // was #193968
const NAVY_SOFT = "#6C5CE7"; // was #3E6BC7
const MINT = "#8B5CF6";      // was #2FAE97 — now violet accent
const TEXT_MUTED = "#6B6483";
const LINE = "#E4DFF5";
const FONT_DISPLAY = "'Plus Jakarta Sans', sans-serif";
const FONT_MONO = "'IBM Plex Mono', monospace";

/* ---------- signal-lock signature motif ---------- */
const SignalLock = ({ locked }) => (
  <Box sx={{ position: "relative", width: 84, height: 84, mx: "auto", mb: 2 }}>
    <svg width="84" height="84" viewBox="0 0 84 84" style={{ position: "absolute", inset: 0 }}>
      {[34, 26, 18].map((r, i) => (
        <circle
          key={r}
          cx="42"
          cy="42"
          r={r}
          fill="none"
          stroke={locked ? MINT : NAVY_SOFT}
          strokeWidth="1.4"
          opacity={locked ? 0.5 - i * 0.1 : 0.32 - i * 0.07}
          style={{
            transformOrigin: "42px 42px",
            animation: locked ? "none" : `pulseRing 2.4s ease-out ${i * 0.5}s infinite`,
          }}
        />
      ))}
    </svg>
    <Box sx={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <Box
        sx={{
          width: 40,
          height: 40,
          borderRadius: "12px",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: locked ? `linear-gradient(135deg, ${MINT}, #23927E)` : `linear-gradient(135deg, ${NAVY}, ${NAVY_SOFT})`,
          boxShadow: locked ? `0 8px 18px rgba(47,174,151,0.35)` : `0 8px 18px rgba(25,57,104,0.28)`,
          transition: "all .4s ease",
        }}
      >
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
          <path d="M12 2 4 5v6c0 5 3.4 9 8 11 4.6-2 8-6 8-11V5l-8-3Z" fill="#fff" />
          {locked && (
            <path d="M8.5 12.2l2.4 2.4 4.6-4.9" stroke={MINT} strokeWidth="1.6" fill="none" strokeLinecap="round" strokeLinejoin="round" />
          )}
        </svg>
      </Box>
    </Box>
    <style>{`
      @keyframes pulseRing {
        0% { opacity: 0.5; transform: scale(0.9); }
        70% { opacity: 0; transform: scale(1.15); }
        100% { opacity: 0; transform: scale(1.15); }
      }
    `}</style>
  </Box>
);

/* ---------- step label ---------- */
const StepTag = ({ n, label }) => (
  <Box sx={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 1, mb: 1.5 }}>
    <Box
      sx={{
        fontFamily: FONT_MONO,
        fontSize: 11,
        letterSpacing: "1.5px",
        color: MINT,
        border: `1px solid rgba(47,174,151,0.35)`,
        backgroundColor: "rgba(47,174,151,0.06)",
        borderRadius: "20px",
        px: 1.2,
        py: 0.3,
      }}
    >
      STEP {n}/2
    </Box>
    <Typography sx={{ fontFamily: FONT_MONO, fontSize: 11, letterSpacing: "1.5px", color: TEXT_MUTED }}>
      {label}
    </Typography>
  </Box>
);

/* ---------- 6-cell mono OTP input ---------- */
const OtpCells = ({ value, onChange, onEnter, inputRef }) => {
  const cells = Array.from({ length: 6 });
  return (
    <Box sx={{ position: "relative", display: "flex", justifyContent: "center", gap: 1.1, mb: 0.5 }}>
      <TextField
        inputRef={inputRef}
        value={value}
        onChange={(e) => onChange(e.target.value.replace(/\D/g, "").slice(0, 6))}
        onKeyDown={(e) => e.key === "Enter" && onEnter()}
        inputProps={{ maxLength: 6, inputMode: "numeric" }}
        sx={{ position: "absolute", inset: 0, opacity: 0, "& input": { cursor: "default" } }}
      />
      {cells.map((_, i) => {
        const filled = i < value.length;
        const active = i === value.length;
        return (
          <Box
            key={i}
            onClick={() => inputRef.current?.focus()}
            sx={{
              width: 40,
              height: 48,
              borderRadius: "10px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontFamily: FONT_MONO,
              fontSize: 20,
              fontWeight: 600,
              color: NAVY,
              backgroundColor: "#F3F8FF",
              border: active ? `1.5px solid ${MINT}` : filled ? `1.5px solid rgba(47,174,151,0.45)` : `1.5px solid ${LINE}`,
              boxShadow: active ? `0 0 0 3px rgba(47,174,151,0.15)` : "none",
              transition: "all .15s ease",
              cursor: "text",
            }}
          >
            {value[i] || ""}
          </Box>
        );
      })}
    </Box>
  );
};

const PpiStatusPage = () => {
  const { setGlobalLoader, setCurrentPage, setBeneficiaryList } = usePpiBankTransfer();

  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [openOtpPopup, setOpenOtpPopup] = useState(false);
  const [sendOtpLoading, setSendOtpLoading] = useState(false);
  const [verifyOtpLoading, setVerifyOtpLoading] = useState(false);
  const otpInputRef = useRef(null);

  useEffect(() => {
    const savedMobile = localStorage.getItem("mobile")?.slice(-10);
    if (savedMobile) setMobile(savedMobile);
  }, []);

  // Lock page scroll while this screen is mounted — position: fixed on
  // the outer Box (below) removes this component from document flow,
  // but a parent layout (PpiPageLayout's header/padding) can still add
  // height above/below it, which would scroll the *document* even
  // though this component itself never does. Locking html/body directly
  // guarantees no page scroll regardless, and is undone on unmount.
  useEffect(() => {
    const { body, documentElement: html } = document;
    const prevBodyOverflow = body.style.overflow;
    const prevHtmlOverflow = html.style.overflow;
    const prevBodyHeight = body.style.height;
    const prevHtmlHeight = html.style.height;

    body.style.overflow = "hidden";
    html.style.overflow = "hidden";
    body.style.height = "100%";
    html.style.height = "100%";

    return () => {
      body.style.overflow = prevBodyOverflow;
      html.style.overflow = prevHtmlOverflow;
      body.style.height = prevBodyHeight;
      html.style.height = prevHtmlHeight;
    };
  }, []);

  const handleProceed = async () => {
    if (sendOtpLoading) return;
    if (mobile.length !== 10) return toast.error("Enter valid 10 digit mobile number");

    localStorage.setItem("mobile", mobile);
    setSendOtpLoading(true);
    setGlobalLoader(true);

    try {
      const res = await checkVerifyRemitter({ mobile });
      const apiData = res?.data?.data;

      if (apiData?.statuscode === "OTP") {
        toast.success("OTP Sent Successfully");
        setOpenOtpPopup(true);
      } else if (apiData?.statuscode === "ERR") {
        toast.error(apiData?.status || "OTP request failed");
      } else {
        toast.error("Unexpected response from server");
      }
    } catch (error) {
      toast.error(error?.response?.data?.message || "Failed to send OTP. Please try again.");
    } finally {
      setSendOtpLoading(false);
      setGlobalLoader(false);
    }
  };

  const handleVerifyOtp = async () => {
    if (verifyOtpLoading) return;
    if (!otp) return toast.error("Enter OTP");

    setVerifyOtpLoading(true);
    setGlobalLoader(true);

    try {
      const res = await checkVerifyRemitter({ mobile, otp });
      const responseBody = res?.data?.data;
      const statusCode = responseBody?.statuscode;

      if (statusCode === "TXN") {
        toast.success("OTP Verified!");
        setBeneficiaryList(responseBody?.data);
        setOpenOtpPopup(false);
        setCurrentPage("ppi-send-money");
      } else if (statusCode === "RNF") {
        toast.info("Remitter Not Found. Please Register.");
        setOpenOtpPopup(false);
        setCurrentPage("ppi-add-customer");
      } else {
        toast.error(responseBody?.status || "Verification Failed");
      }
    } catch {
      toast.error("Invalid OTP");
    } finally {
      setVerifyOtpLoading(false);
      setGlobalLoader(false);
    }
  };

  const inputSx = {
    "& .MuiOutlinedInput-root": { borderRadius: "12px", backgroundColor: "#F3F8FF" },
    "& .MuiInputLabel-root": { color: TEXT_MUTED, fontFamily: FONT_DISPLAY },
    "& .MuiInputLabel-root.Mui-focused": { color: MINT },
    "& .MuiOutlinedInput-notchedOutline": { borderColor: LINE },
    "&:hover .MuiOutlinedInput-notchedOutline": { borderColor: NAVY_SOFT },
    "&.Mui-focused .MuiOutlinedInput-notchedOutline": { borderColor: MINT },
    "& input": { fontFamily: FONT_MONO, letterSpacing: "2px", color: NAVY },
  };

  const primaryBtnSx = {
    py: 1.3,
    width: "100%",
    borderRadius: "12px",
    fontWeight: 700,
    textTransform: "none",
    fontSize: 15,
    fontFamily: FONT_DISPLAY,
    background: `linear-gradient(135deg, ${MINT}, #23927E)`,
    color: "#fff",
    boxShadow: `0 8px 20px rgba(47,174,151,0.28)`,
    "&:hover": { background: `linear-gradient(135deg, #35C0A6, #1F8371)`, boxShadow: `0 10px 24px rgba(47,174,151,0.36)` },
    "&.Mui-disabled": { background: "#E1E9F3", color: "#A9B7CC" },
  };

  return (
     
    <PpiPageLayout title="PPI Bank Transfer">
      <Box
  sx={{
    position: "fixed",
    inset: 0,
    width: "100%",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    py: 6,
    px: 2,
    overflow: "hidden",
   backgroundImage: `
  linear-gradient(
    rgba(245,244,252,0.72),
    rgba(245,244,252,0.72)
  ),
  url(${ppibank})
`,
backgroundSize: "cover",
backgroundPosition: "center",
backgroundRepeat: "no-repeat",
backgroundAttachment: "fixed",
  }}
>
  {/* soft dot-grid — unchanged */}
  <Box
    sx={{
      position: "absolute",
      inset: 0,
      opacity: 0.55,
      backgroundImage: `radial-gradient(rgba(42,35,89,0.08) 1px, transparent 1px)`,
      backgroundSize: "24px 24px",
      pointerEvents: "none",
    }}
  />

  {/* large identity/security motif — shield, fingerprint, signal rings,
      lock — scattered at generous scale so it reads as a deliberate
      scene rather than a repeating texture */}
  <Box sx={{ position: "absolute", inset: 0, zIndex: 0, pointerEvents: "none" }}>
    <svg width="100%" height="100%" style={{ position: "absolute", inset: 0 }} preserveAspectRatio="xMidYMid slice">
      <g fill="none" stroke="#2A2359" strokeWidth="1.4" opacity="0.06">
        {/* shield, top-left */}
        <path d="M60 40 L110 55 V95 C110 130 85 155 60 165 C35 155 10 130 10 95 V55 Z" />
        <path d="M35 100 L52 118 L88 78" strokeWidth="2.2" />

        {/* fingerprint, bottom-right */}
        <g transform="translate(880,620)">
          <circle r="46" />
          <circle r="34" />
          <circle r="22" />
          <path d="M-46 0 a46 46 0 0 1 46 -46" />
          <path d="M46 8 a46 46 0 0 1 -30 40" />
        </g>

        {/* signal rings, top-right */}
        <g transform="translate(920,90)">
          <circle r="30" />
          <circle r="50" />
          <circle r="70" />
        </g>

        {/* padlock, bottom-left */}
        <g transform="translate(90,700)">
          <rect x="-26" y="0" width="52" height="42" rx="8" />
          <path d="M-16 0 v-16 a16 16 0 0 1 32 0 v16" />
          <circle cy="20" r="4" />
        </g>

        {/* OTP-style dashed line connecting the corners, faint */}
        <path d="M120 120 Q 500 300 850 150" strokeDasharray="2 10" strokeWidth="1.2" />
        <path d="M150 650 Q 480 500 860 600" strokeDasharray="2 10" strokeWidth="1.2" />
      </g>
    </svg>
  </Box>

  {/* card stays exactly as before */}
  <Box
    sx={{
      position: "relative",
      zIndex: 1,
      width: "100%",
      maxWidth: 380,
      maxHeight: "92vh",
      overflowY: "auto",
      p: 4,
      borderRadius: "20px",
      backgroundColor: PANEL,
      border: `1px solid ${LINE}`,
      boxShadow: "0 20px 48px rgba(42,35,89,0.14)",
      textAlign: "center",
    }}
  >
          <SignalLock locked={false} />
          <StepTag n={1} label="MOBILE NUMBER" />
          <Typography sx={{ fontFamily: FONT_DISPLAY, fontSize: 20, fontWeight: 700, color: NAVY, mb: 0.5 }}>
            Verify your identity
          </Typography>
          <Typography sx={{ fontFamily: FONT_DISPLAY, fontSize: 13.5, color: TEXT_MUTED, mb: 3.5 }}>
            Enter your registered mobile number to receive a one-time code.
          </Typography>

          <TextField
            fullWidth
            label="Mobile Number"
            value={mobile}
            onChange={(e) => setMobile(e.target.value.replace(/\D/g, ""))}
            inputProps={{ maxLength: 10 }}
            onKeyDown={(e) => {
              if (e.key === "Enter") {
                e.preventDefault();
                if (!sendOtpLoading) handleProceed();
              }
            }}
            className="mui-autofill-fix"
            sx={{ mb: 3, ...inputSx }}
          />

          <Button onClick={handleProceed} disabled={sendOtpLoading} sx={primaryBtnSx}>
            {sendOtpLoading ? <CircularProgress size={22} sx={{ color: "#fff" }} /> : "Send OTP"}
          </Button>
        </Box>
      </Box>

      {/* OTP DIALOG */}
      <Dialog
        open={openOtpPopup}
        disableRestoreFocus
        onClose={() => {
          setOpenOtpPopup(false);
          setOtp("");
        }}
        fullWidth
        maxWidth="xs"
        TransitionProps={{ onEntered: () => otpInputRef.current?.focus() }}
        PaperProps={{
          sx: {
            borderRadius: "20px",
            backgroundColor: PANEL,
            backgroundImage: `radial-gradient(circle at 85% 0%, rgba(139,92,246,0.10), transparent 55%)`,
            border: `1px solid ${LINE}`,
            p: 1,
          },
        }}
      >
        <DialogContent sx={{ p: 3 }}>
          <SignalLock locked={otp.length === 6} />
          <StepTag n={2} label="ENTER CODE" />
          <Typography sx={{ fontFamily: FONT_DISPLAY, fontSize: 18, fontWeight: 700, color: NAVY, textAlign: "center", mb: 0.5 }}>
            Enter the 6-digit code
          </Typography>
          <Typography sx={{ fontFamily: FONT_DISPLAY, fontSize: 13, color: TEXT_MUTED, textAlign: "center", mb: 3 }}>
            Sent to your registered mobile number
          </Typography>

          <OtpCells value={otp} onChange={setOtp} onEnter={handleVerifyOtp} inputRef={otpInputRef} />

          <Button fullWidth disabled={verifyOtpLoading} onClick={handleVerifyOtp} sx={{ ...primaryBtnSx, mt: 3.5 }}>
            {verifyOtpLoading ? <CircularProgress size={22} sx={{ color: "#fff" }} /> : "Verify OTP"}
          </Button>
        </DialogContent>
      </Dialog>
    </PpiPageLayout>
  );
};

export default PpiStatusPage;